class Solution:
    def sortList(self, head):
        if not head or not head.next:
            return head
        # 求长度
        n = 0
        cur = head
        while cur:
            n += 1
            cur = cur.next
        dummy = ListNode(0, head)
        size = 1
        while size < n:
            prev = dummy
            cur = dummy.next
            while cur:
                left = cur
                right = self._split(left, size)
                cur = self._split(right, size)
                prev.next = _merge(left, right)
                while prev.next:
                    prev = prev.next
            size *= 2
        return dummy.next

    @staticmethod
    def _split(head, size):
        """走 size 步,在第 size 个之后切断,返回切断后的下一段头。"""
        for _ in range(size - 1):
            if not head:
                break
            head = head.next
        if not head:
            return None
        nxt = head.next
        head.next = None
        return nxt

